// 纵 0 横 1
ll dp[2][2005][2005], pre[2][2005][2005], suf[2][2005][2005];
string s[2005];
void solve(int CASE)
{
	int n, m; cin >> n >> m;
	fa(i, 1, n)cin >> s[i], s[i] = ' ' + s[i];
	fa(j, 1, m)fb(i, n, 1)suf[0][i][j] = suf[0][i + 1][j] + (s[i][j] == 'R');
	fa(i, 1, n)fb(j, m, 1)suf[1][i][j] = suf[1][i][j + 1] + (s[i][j] == 'R');

	dp[0][1][1] = dp[1][1][1] = 1;
	pre[0][1][1] = 1, pre[1][1][1] = 1;
	fa(i, 1, n)fa(j, 1, m) {
		if (i == 1 and j == 1)continue;

		int len = m - j + 1;
		int l = 1, r = j - 1, res = 0;
		while (l <= r) {
			int mid = l + r >> 1;
			if (suf[1][i][mid + 1] < len) {
				res = mid;
				r = mid - 1;
			}
			else l = mid + 1;
		}
		if (res)dp[1][i][j] = ((pre[0][i][j - 1] - pre[0][i][res - 1]) % mod + mod) % mod;

		len = n - i + 1;
		l = 1, r = i - 1, res = 0;
		while (l <= r) {
			int mid = l + r >> 1;
			if (suf[0][mid + 1][j] < len) {
				res = mid;
				r = mid - 1;
			}
			else l = mid + 1;
		}
		if (res)dp[0][i][j] = ((pre[1][i - 1][j] - pre[1][res - 1][j]) % mod + mod) % mod;

		pre[1][i][j] = (pre[1][i - 1][j] + dp[1][i][j]) % mod;
		pre[0][i][j] = (pre[0][i][j - 1] + dp[0][i][j]) % mod;
	}

	if (n == 1 and m == 1)cout << 1 << endl;
	else cout << (dp[0][n][m] + dp[1][n][m]) % mod << endl;
	return;
}
